# Python Retry Decorator with Exponential Backoff

```python
import functools
import time
import logging
from typing import Callable, Type, Tuple, TypeVar, Any, Optional, cast

# Type variable for the return type of the decorated function
T = TypeVar('T')

def retry(
    max_attempts: int = 3, 
    backoff_factor: float = 2, 
    exceptions: Tuple[Type[Exception], ...] = (Exception,)
) -> Callable[[Callable[..., T]], Callable[..., T]]:
    """
    Decorator that retries a function on failure with exponential backoff.

    Args:
        max_attempts: Maximum number of attempts to retry the function.
        backoff_factor: Factor by which the delay increases with each retry.
                        delay = backoff_factor ** (attempt - 1)
        exceptions: Tuple of exception types that trigger a retry.

    Returns:
        A decorator function that wraps the original function with retry logic.

    Example:
        @retry(max_attempts=3, backoff_factor=2, exceptions=(ConnectionError, TimeoutError))
        def fetch_data(url: str) -> dict:
            # Function implementation
            pass
    """
    def decorator(func: Callable[..., T]) -> Callable[..., T]:
        @functools.wraps(func)
        def wrapper(*args: Any, **kwargs: Any) -> T:
            last_exception: Optional[Exception] = None

            for attempt in range(1, max_attempts + 1):
                try:
                    return func(*args, **kwargs)
                except exceptions as e:
                    last_exception = e

                    if attempt < max_attempts:
                        delay = backoff_factor ** (attempt - 1)
                        logging.warning(
                            f"Attempt {attempt}/{max_attempts} for {func.__name__} failed: {str(e)}. "
                            f"Retrying in {delay:.2f} seconds..."
                        )
                        time.sleep(delay)
                    else:
                        logging.error(
                            f"All {max_attempts} attempts for {func.__name__} failed. "
                            f"Last error: {str(e)}"
                        )

            # If we've exhausted all attempts, raise the last exception
            if last_exception is not None:
                raise last_exception

            # This line should never be reached, but is needed for type checking
            raise RuntimeError("Unexpected error in retry decorator")

        return cast(Callable[..., T], wrapper)

    return decorator
```

## Example Usage

```python
import random

# Example with a function that returns a value
@retry(max_attempts=3, backoff_factor=2, exceptions=(ValueError, RuntimeError))
def fetch_data(url: str) -> dict:
    """Simulate fetching data from a URL with possible failures."""
    # Simulate random failures
    if random.random() < 0.7:
        raise ValueError("Connection error")
    return {"status": "success", "data": f"Data from {url}"}

# Example with a void function
@retry(max_attempts=5, backoff_factor=1.5, exceptions=(IOError,))
def save_data(data: dict, filename: str) -> None:
    """Simulate saving data to a file with possible failures."""
    if random.random() < 0.6:
        raise IOError("Disk full")
    print(f"Data saved to {filename}")

# Usage
try:
    result = fetch_data("https://example.com/api")
    print(f"Received: {result}")

    save_data({"key": "value"}, "output.json")
except Exception as e:
    print(f"Operation failed after all retries: {e}")
```

The decorator handles functions with any return type through the use of the generic type variable `T`. It preserves the original function's signature and docstring using `functools.wraps`. The exponential backoff increases the delay between retries, and the decorator logs information about retry attempts.

